import { Box, Flex, Image, Text } from "@chakra-ui/react";
import { Link } from "react-router-dom";
import { FaStar } from "react-icons/fa";

const Card = ({ title, category, description, _id, img }) => {
  const fallbackImages = [
    "https://img-c.udemycdn.com/course/480x270/1565838_e54e_16.jpg",
    "https://img-c.udemycdn.com/course/480x270/950390_270f_3.jpg",
    "https://img-c.udemycdn.com/course/480x270/2776760_f176_10.jpg",
  ];

  const image =
    img || fallbackImages[Math.floor(Math.random() * fallbackImages.length)];

  return (
    <Link to={`/course/${_id}`}>
      <Box
        cursor="pointer"
        _hover={{ transform: "translateY(-5px)", transition: "0.3s" }}
      >
        {/* IMAGE */}
        <Image
          src={image}
          alt={title}
          borderRadius="md"
          objectFit="cover"
          w="100%"
          h="160px"
        />

        {/* CONTENT */}
        <Box mt={3}>
          {/* TITLE */}
          <Text
            fontWeight="bold"
            fontSize="md"
            noOfLines={2}
            mb={1}
          >
            {title}
          </Text>

          {/* INSTRUCTOR (fake for now) */}
          <Text fontSize="sm" color="gray.500">
            By SRM Instructor
          </Text>

          {/* RATING */}
          <Flex align="center" gap={1} mt={1}>
            <Text fontSize="sm" fontWeight="bold" color="#b4690e">
              4.5
            </Text>

            <FaStar color="#f4c150" />

            <Text fontSize="sm" color="gray.500">
              (1,200)
            </Text>
          </Flex>

          {/* CATEGORY */}
          <Text
            fontSize="xs"
            color="gray.500"
            mt={1}
            textTransform="capitalize"
          >
            {category}
          </Text>

          {/* PRICE */}
          <Text fontWeight="bold" mt={2}>
            ₫199,000
          </Text>
        </Box>
      </Box>
    </Link>
  );
};

export default Card;
